class Solution:
    def sortVowels(self, s):
        vowels = set('aeiouAEIOU')
        idxs = [i for i, c in enumerate(s) if c in vowels]
        vals = sorted(s[i] for i in idxs)
        arr = list(s)
        for i, v in zip(idxs, vals):
            arr[i] = v
        return ''.join(arr)

