class Solution:
    def sortVowels(self, s):
        vowels = set('aeiouAEIOU')
        chars = list(s)
        vowel_chars = sorted(c for c in chars if c in vowels)
        it = iter(vowel_chars)
        result = []
        for c in chars:
            if c in vowels:
                result.append(next(it))
            else:
                result.append(c)
        return ''.join(result)

