var sortVowels = function(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);
    const chars = s.split('');
    const vowelChars = chars.filter(c => vowels.has(c)).sort((a, b) => a.charCodeAt(0) - b.charCodeAt(0));
    let idx = 0;
    const result = [];
    for (const c of chars) {
        if (vowels.has(c)) {
            result.push(vowelChars[idx]);
            idx++;
        } else {
            result.push(c);
        }
    }
    return result.join('');
};
